import re


def adapt(a_payload):
    if not isinstance(a_payload, dict):
        raise ValueError("payload must be a dict")

    if "customer_id" not in a_payload:
        raise KeyError("missing 'customer_id'")

    raw = a_payload["customer_id"]

    if isinstance(raw, bool):
        # bool is a subclass of int; reject it as a non-integer identifier
        raise ValueError("invalid customer_id: boolean is not a valid identifier")

    if isinstance(raw, int):
        return {"customerId": raw}

    if isinstance(raw, str):
        s = raw.strip()

        # Pure integer string, e.g. "42" or "-42"
        if re.fullmatch(r"[+-]?\d+", s):
            return {"customerId": int(s)}

        # Prefixed / decorated identifier, e.g. "CUST-00042".
        # Extract the digit run and interpret it as the integer PK.
        digit_groups = re.findall(r"\d+", s)
        if len(digit_groups) == 1:
            return {"customerId": int(digit_groups[0])}

        raise ValueError(f"cannot derive integer customerId from: {raw!r}")

    raise ValueError(f"unsupported customer_id type: {type(raw).__name__}")

