    # Currencies without minor units (values are already in major units).
    # These use 0 decimal places per ISO 4217.
    zero_decimal = {
        "JPY", "KRW", "VND", "CLP", "PYG", "ISK", "HUF",
        "UGX", "RWF", "XOF", "XAF", "XPF", "GNF", "KMF",
        "DJF", "BIF", "VUV", "MGA",
    }
    # Currencies with 3 decimal places (minor unit = 1/1000).
    three_decimal = {
        "BHD", "IQD", "JOD", "KWD", "LYD", "OMR", "TND",
    }

    if not isinstance(a_payload, dict):
        raise TypeError("payload must be a dict")

    currency = a_payload.get("currency")
    if not isinstance(currency, str) or not currency.strip():
        raise ValueError("missing or invalid currency")
    currency = currency.strip().upper()

