    else:
        sku = str(sku_val)

    # --- qty ---
    # "stock" is the only plausible quantity-bearing field in the sample.
    # Convention for its value is unknown, so coerce defensively rather than assume.
    def to_qty(v):
        # Missing -> 0
        if v is None:
            return 0
        # Bools are ints in Python; treat explicitly (True->1, False->0)
        if isinstance(v, bool):
            return int(v)
        # Real integers
        if isinstance(v, int):
            return v
        # Floats: take the integer part (do not round up phantom stock)
        if isinstance(v, float):
            try:
                return int(v)
            except (ValueError, OverflowError):
                return 0
        # Strings: parse digits, tolerate whitespace / decimals / sign
        if isinstance(v, str):
            s = v.strip()
            if not s:
                return 0
            try:
                return int(s)
            except ValueError:
                try:
                    return int(float(s))
                except (ValueError, OverflowError):
                    return 0
        # Anything else: unknown -> 0
        return 0

    qty = to_qty(src.get("stock"))
    # qty must be a non-negative int for a warehouse count
    if qty < 0:
        qty = 0

    # --- tracked ---
    # No source field maps to this. A warehouse that carries stock counts is,
    # by default, tracking inventory. Commit to True as the safe default,
