    """
    Adapt a System-A payload into this system's required shape: {"celsius": float}.

    Unknowns and how they're handled:
      - System A gives a key "temp" with a numeric value, but the unit
        (Celsius vs Fahrenheit) is NOT specified anywhere.
      - The sample value -40.0 is deliberately ambiguous: it is the one point
        where Celsius and Fahrenheit are numerically equal (-40 C == -40 F),
        so it gives NO information to disambiguate the scale.
      - Because we cannot assume System A's convention and the value could be
        plausible on either scale, we must pick a rule that fails safely.

    Decision:
      - We CANNOT reliably tell the unit from a single number, so we do not
        silently convert. Converting a Celsius reading as if it were Fahrenheit
        (or vice-versa) would corrupt process-control data.
      - However, the requirement says our dashboard stores Celsius. The safest
        committed rule: treat the incoming value as already-Celsius UNLESS the
        payload explicitly declares Fahrenheit. This avoids inventing a
        conversion we can't justify, while still honoring an explicit unit hint
        if System A happens to send one.
    """
    # Locate the temperature value robustly.
    value = None
    for key in ("temp", "temperature", "value", "celsius", "fahrenheit"):
        if isinstance(a_payload, dict) and key in a_payload:
            value = a_payload[key]
            break

    if value is None:
        # Nothing usable; commit to a defined, safe output.
        return {"celsius": 0.0}

    try:
        value = float(value)
    except (TypeError, ValueError):
        return {"celsius": 0.0}

    # Look for any explicit unit hint. We only convert when explicitly told.
    unit = None
    if isinstance(a_payload, dict):
        for uk in ("unit", "units", "scale"):
            if uk in a_payload and isinstance(a_payload[uk], str):
                unit = a_payload[uk].strip().lower()
                break
        # If the value came under a key that itself names the unit, honor it.
        if unit is None:
            if "fahrenheit" in a_payload:
                unit = "f"
            elif "celsius" in a_payload:
                unit = "c"

    is_fahrenheit = False
    if unit is not None:
        if unit in ("f", "fahrenheit", "°f", "degf", "deg_f"):
            is_fahrenheit = True
        elif unit in ("c", "celsius", "°c", "degc", "deg_c"):
            is_fahrenheit = False

    if is_fahrenheit:
        celsius = (value - 32.0) * 5.0 / 9.0
    else:
        # No explicit Fahrenheit hint: treat as Celsius (do not fabricate a conversion).
        celsius = value

    return {"celsius": round(celsius, 2)}

